diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index fdadf729fbd5..82df1ee49161 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -7885,6 +7885,7 @@ static Instruction *foldFCmpFNegCommonOp(FCmpInst &I) {
   return new FCmpInst(Pred, Op0, Zero, "", &I);
 }

+
 Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
   bool Changed = false;

@@ -8071,6 +8072,32 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
   if (Instruction *R = foldFabsWithFcmpZero(I, *this))
     return R;

+  // Fold fcmp pred (select (fcmp oge X, 0.0), X, (fneg X)), 0.0 -> fcmp pred X, 0.0
+  // This is the absolute value pattern: abs(X) = (X >= 0) ? X : -X.
+  Value *CondLHS, *CondRHS;
+  FCmpInst::Predicate CondPred;
+  Value *TrueVal, *FalseVal;
+  if (match(Op0, m_Select(m_FCmp(CondPred, m_Value(CondLHS), m_Value(CondRHS)),
+                          m_Value(TrueVal), m_Value(FalseVal))) &&
+      match(Op1, m_AnyZeroFP())) {
+    // Check if the select is choosing between X and -X based on the sign of X.
+    Value *X;
+    if (match(TrueVal, m_Value(X)) && match(FalseVal, m_FNeg(m_Specific(X)))) {
+      // The condition should be a sign test on X.
+      if ((CondPred == FCmpInst::FCMP_OGE && match(CondRHS, m_PosZeroFP()) &&
+           CondLHS == X) ||
+          (CondPred == FCmpInst::FCMP_OLT && match(CondRHS, m_PosZeroFP()) &&
+           CondLHS == X) ||
+          (CondPred == FCmpInst::FCMP_OLE && match(CondLHS, m_PosZeroFP()) &&
+           CondRHS == X) ||
+          (CondPred == FCmpInst::FCMP_OGT && match(CondLHS, m_PosZeroFP()) &&
+           CondRHS == X)) {
+        // abs(X) == 0  iff  X == 0.
+        return new FCmpInst(Pred, X, Op1, "", &I);
+      }
+    }
+  }
+
   if (match(Op0, m_FNeg(m_Value(X)))) {
     // fcmp pred (fneg X), C --> fcmp swap(pred) X, -C
     Constant *C;
@@ -8180,3 +8207,4 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {

   return Changed ? &I : nullptr;
 }
+

